create extension if not exists pgcrypto;
create type public.organization_role as enum ('owner','admin','manager','member','viewer','support_agent','sales_representative');
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text, avatar_url text, active_organization_id uuid, onboarding_completed boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.organizations (id uuid primary key default gen_random_uuid(), name text not null, slug text not null unique, company_name text, industry text, created_by uuid not null references auth.users(id), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
alter table public.profiles add constraint profiles_active_organization foreign key (active_organization_id) references public.organizations(id) on delete set null;
create table public.organization_members (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, user_id uuid not null references auth.users(id) on delete cascade, role public.organization_role not null default 'member', created_by uuid references auth.users(id), created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(organization_id,user_id));
create or replace function public.is_org_member(org_id uuid) returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from public.organization_members where organization_id=org_id and user_id=auth.uid())$$;
create or replace function public.has_org_role(org_id uuid, roles public.organization_role[]) returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from public.organization_members where organization_id=org_id and user_id=auth.uid() and role=any(roles))$$;
create table public.projects (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), name text not null, status text not null default 'planning', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.tasks (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), project_id uuid references public.projects(id) on delete set null, title text not null, status text not null default 'backlog', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.customers (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), name text not null, company text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.leads (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), name text not null, stage text not null default 'new', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.meetings (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), title text not null, starts_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.documents (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), title text not null, content jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.support_requests (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), subject text not null, status text not null default 'new', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.conversations (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), title text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.ai_messages (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), conversation_id uuid references public.conversations(id) on delete cascade, role text not null, content text not null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.tool_execution_logs (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid not null references auth.users(id), tool_name text not null, status text not null, input_summary jsonb, output_summary jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.audit_logs (id uuid primary key default gen_random_uuid(), organization_id uuid not null references public.organizations(id) on delete cascade, created_by uuid references auth.users(id), action text not null, target_type text, target_id uuid, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create or replace function public.set_updated_at() returns trigger language plpgsql as $$begin new.updated_at=now(); return new; end;$$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$begin insert into public.profiles(id,full_name) values(new.id,coalesce(new.raw_user_meta_data->>'full_name','')); return new; end;$$;
create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
